--
-- Name: audit_logs; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE public.audit_logs (
    id integer NOT NULL,
    org_id character varying(50),
    user_id character varying(50),
    client_id character varying(100),
    action character varying(100) NOT NULL,
    details jsonb DEFAULT '{}'::jsonb,
    created_at timestamp with time zone,
    uuid uuid NOT NULL,
    session_id character varying(255),
    request_id uuid,
    correlation_id uuid,
    category public.enum_audit_logs_category,
    severity public.enum_audit_logs_severity DEFAULT 'INFO'::public.enum_audit_logs_severity,
    status public.enum_audit_logs_status DEFAULT 'SUCCESS'::public.enum_audit_logs_status NOT NULL,
    message text,
    metadata jsonb DEFAULT '{}'::jsonb,
    source_ip character varying(45),
    destination_ip character varying(45),
    user_agent text,
    geo_location jsonb,
    device_id character varying(255),
    os character varying(100),
    browser character varying(100),
    environment public.enum_audit_logs_environment DEFAULT 'DEVELOPMENT'::public.enum_audit_logs_environment,
    service_name character varying(100) DEFAULT 'auth-service'::character varying,
    risk_score integer DEFAULT 0,
    compliance_tags jsonb DEFAULT '[]'::jsonb,
    immutable_hash character varying(64),
    actor_type public.enum_audit_logs_actor_type DEFAULT 'USER'::public.enum_audit_logs_actor_type,
    affected_entity_type character varying(50),
    affected_entity_id character varying(100),
    auth_method public.enum_audit_logs_auth_method,
    privilege_level public.enum_audit_logs_privilege_level,
    data_classification public.enum_audit_logs_data_classification DEFAULT 'INTERNAL'::public.enum_audit_logs_data_classification,
    duration_ms integer,
    response_code integer,
    node_id character varying(100) DEFAULT '118eaf175409'::character varying,
    trace_id character varying(255),
    span_id character varying(255),
    "timestamp" timestamp with time zone NOT NULL,
    inserted_at timestamp with time zone NOT NULL
);


ALTER TABLE public.audit_logs OWNER TO postgres;

